        try {
            Process process = processBuilder.start();
            process.waitFor();
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }

    public static String getUserInput() {
        // Assume this method gets user input from an untrusted source
        return "127.0.0.1"; // Safe user input without malicious commands
